function B4DUI.F4.Open() local f=B4DUI.UI.CreateFrame("B4D F4",ScrW()*.78,ScrH()*.8); B4DUI.F4.Frame=f; local side=f:Add("DPanel"); side:SetPos(0,59); side:SetSize(210,f:GetTall()-59); side.Paint=function(_,w,h) draw.RoundedBoxEx(14,0,0,w,h,B4DUI.Color("panel2"),false,false,true,false) end; local content=f:Add("DPanel"); content:SetPos(222,74); content:SetSize(f:GetWide()-246,f:GetTall()-96); content.Paint=function(_,w,h) draw.RoundedBox(12,0,0,w,h,Color(0,0,0,35)) end; B4DUI.F4.Content=content; B4DUI.F4.BuildSidebar(side) end
